codeExercises.solution:
import express from 'express';
import cors from 'cors';

const app = express();
const port = 8080;

const whitelist = ['http://localhost:3000', 'https://my-app.com'];

const corsOptions = {
  origin: function (origin, callback) {
    // Cho phép các yêu cầu không có origin (ví dụ: Postman, mobile apps)
    if (!origin) {
      return callback(null, true);
    }
    // Kiểm tra origin có trong whitelist không
    if (whitelist.indexOf(origin) !== -1) {
      callback(null, true);
    } else {
      // Từ chối với lỗi nếu không có trong whitelist
      callback(new Error(`${origin} not allowed by CORS.`));
    }
  }
};

app.use(cors(corsOptions));

app.get('/api/status', (req, res) => {
  res.json({ status: 'OK' });
});

app.listen(port, () => {
  console.log(`Server is running on port ${port}`);
});
